import sys
import re

def solve() -> None:
    s = sys.stdin.read()
    if s.endswith('\n'):
        s = s[:-1]

    tokens = re.split(r'(\s+)', s)

    for i, t in enumerate(tokens):
        if t.isspace() or t == '':
            continue
        if len(t) > 2:
            tokens[i] = t[0].upper() + t[1:].lower()

    print(''.join(tokens))

