    solve()

import sys

def options(ch: str):
    if ch == 'a':
        return {'b'}
    if ch == 'z':
        return {'y'}
    return {chr(ord(ch) - 1), chr(ord(ch) + 1)}

def can_be_palindrome(s: str) -> bool:
    n = len(s)
    for i in range(n // 2):
        j = n - 1 - i
        if not (options(s[i]) & options(s[j])):
            return False
    return True

def solve():
    s = sys.stdin.readline().strip()
    print("True" if can_be_palindrome(s) else "False")

if __name__ == "__main__":
    solve()

