def solve() -> None:
    s = sys.stdin.readline().strip()
    EX = {'c': -1, 'o': -1, 'd': -3, 'e': -4}
    VOW = set('aeiou')
    res = []
    for ch in s:
        if ch in EX:
            shift = EX[ch]
            new_idx = (ord(ch) - 97 + shift) % 26
        elif ch in VOW:
            new_idx = (ord(ch) - 97 - 5) % 26
        else:
            new_idx = (ord(ch) - 97 + 9) % 26
        new_ch = chr(new_idx + 97)
        if new_ch in EX:
            res.append(ch)
        else:
            res.append(new_ch)
    sys.stdout.write(''.join(res))

