def is_madhav(arr):
    n = len(arr)
    if n < 2:
        return False

    # find m such that m*(m+1)//2 == n
    m = int((math.isqrt(8 * n + 1) - 1) // 2)
    if m * (m + 1) // 2 != n:
        return False

    target = arr[0]
    idx = 1
    for size in range(2, m + 1):
        if idx + size > n:
            return False
        if sum(arr[idx: idx + size]) != target:
            return False
        idx += size
    return True

