    main()

import sys

def solve() -> None:
    s = sys.stdin.read().replace('\n', '')
    n = len(s)

    # find first '['
    L = -1
    for i, ch in enumerate(s):
        if ch == '[':
            L = i
            break

    # find last ']'
    R = -1
    for i in range(n - 1, -1, -1):
        if s[i] == ']':
            R = i
            break

    if L == -1 or R == -1 or L > R:
        print(-1)
        return

    # first ':' after L
    i = -1
    for idx in range(L + 1, n):
        if s[idx] == ':':
            i = idx
            break

    # last ':' before R
    k = -1
    for idx in range(R - 1, -1, -1):
        if s[idx] == ':':
            k = idx
            break

    if i == -1 or k == -1 or i >= k:
        print(-1)
        return

    cnt = 0
    for idx in range(i + 1, k):
        if s[idx] == '|':
            cnt += 1

    print(4 + cnt)

