    solve()

import sys, ast

def is_strictly_increasing(arr):
    for i in range(1, len(arr)):
        if arr[i] <= arr[i - 1]:
            return False
    return True

def solve():
    line = sys.stdin.readline().strip()
    if not line:
        print("False")
        return
    try:
        seq = ast.literal_eval(line)
    except Exception:
        line = line.strip('[]')
        seq = [int(x) for x in line.replace(',', ' ').split()] if line else []
    n = len(seq)

    viol = -1
    for i in range(1, n):
        if seq[i] <= seq[i - 1]:
            viol = i
            break

    if viol == -1:
        print("True")
        return

    # delete seq[viol-1]
    cand1 = seq[:viol - 1] + seq[viol:]
    if is_strictly_increasing(cand1):
        print("True")
        return

    # delete seq[viol]
    cand2 = seq[:viol] + seq[viol + 1:]
    if is_strictly_increasing(cand2):
        print("True")
        return

    print("False")

if __name__ == "__main__":
    solve()

