def solve() -> None:
    data = sys.stdin.read().strip()
    if not data:
        return
    # Parse input list
    if data[0] == '[':
        arr = ast.literal_eval(data)
    else:
        arr = [int(x) for x in data.replace(',', ' ').split()]
    n = len(arr)

    best_product = None
    best_removed = None

    for i in range(n):
        prod = 1
        for j in range(n):
            if j != i:
                prod *= arr[j]
        if (best_product is None or
            prod > best_product or
            (prod == best_product and arr[i] < best_removed)):
            best_product = prod
            best_removed = arr[i]

    print(best_removed)

