import sys
from functools import lru_cache

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n_str = data[0]
    k = int(data[1])
    L = len(n_str)

    @lru_cache(maxsize=None)
    def dp(pos: int, cnt: int, tight: bool) -> int:
        if cnt > k:
            return 0
        if pos == L:
            return 1 if cnt == k else 0
        limit = int(n_str[pos]) if tight else 9
        total = 0
        for d in range(limit + 1):
            new_cnt = cnt + (d != 0)
            if new_cnt > k:
                continue
            total += dp(pos + 1, new_cnt, tight and d == limit)
        return total

    result = dp(0, 0, True)
    print(result)

if __name__ == "__main__":
    solve()

