import sys

def solve() -> None:
    s = sys.stdin.readline().rstrip('\n')
    n = len(s)

    # first '['
    try:
        i = s.index('[')
    except ValueError:
        print(-1)
        return

    # first ':' after i
    j = -1
    for pos in range(i + 1, n):
        if s[pos] == ':':
            j = pos
            break
    if j == -1:
        print(-1)
        return

    # last ']'
    try:
        l = s.rindex(']')
    except ValueError:
        print(-1)
        return

    # last ':' before l
    k = -1
    for pos in range(l - 1, -1, -1):
        if s[pos] == ':':
            k = pos
            break
    if k == -1:
        print(-1)
        return

    # check order
    if not (i < j < k < l):
        print(-1)
        return

    # count '|' between the two colons
    cnt = s[j + 1:k].count('|')
    print(4 + cnt)

