import sys

def solve() -> None:
    lines = sys.stdin.read().splitlines()
    if not lines:
        return
    s1 = lines[0] if len(lines) > 0 else ''
    s2 = lines[1] if len(lines) > 1 else ''

    cnt1 = [0] * 26
    cnt2 = [0] * 26

    for ch in s1:
        if 'a' <= ch <= 'z':
            cnt1[ord(ch) - 97] += 1
    for ch in s2:
        if 'a' <= ch <= 'z':
            cnt2[ord(ch) - 97] += 1

    pieces = []
    for i in range(26):
        c1, c2 = cnt1[i], cnt2[i]
        mx = c1 if c1 > c2 else c2
        if mx <= 1:
            continue
        if c1 > c2:
            pref = '1'
        elif c2 > c1:
            pref = '2'
        else:
            pref = '='
        letter = chr(97 + i)
        piece = f"{pref}:{letter * mx}"
        pieces.append((-mx, piece))

    pieces.sort()
    result = '/'.join(p[1] for p in pieces)
    sys.stdout.write(result)

if __name__ == "__main__":
    solve()

