import sys, math

def factor_exponents(n: int):
    exps = []
    d = 2
    while d * d <= n:
        if n % d == 0:
            cnt = 0
            while n % d == 0:
                n //= d
                cnt += 1
            exps.append(cnt)
        d += 1 if d == 2 else 2
    if n > 1:
        exps.append(1)
    return exps

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    k = int(data[1])

    exps = factor_exponents(n)
    ans = 1
    for e in exps:
        ans *= math.comb(e + k - 1, k - 1)
    print(ans)

