def solve() -> None:
    line = sys.stdin.read().strip()
    nums = list(map(int, re.findall(r'\d+', line)))
    if not nums:
        print(-1)
        return

    g = nums[0]
    for v in nums[1:]:
        g = math.gcd(g, v)
    if g != 1:
        print(-1)
        return

    if 1 in nums:
        print(0)
        return

    a_min = min(nums)
    a_max = max(nums)
    limit = a_min * a_max

    reachable = bytearray(limit + 1)
    reachable[0] = 1
    for c in nums:
        for i in range(c, limit + 1):
            if reachable[i - c]:
                reachable[i] = 1

    ans = 0
    for i in range(limit, -1, -1):
        if not reachable[i]:
            ans = i
            break
    print(ans)

