def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    m = int(next(it))

    parent = list(range(m + 1))
    rank = [0] * (m + 1)

    def find(x):
        while parent[x] != x:
            parent[x] = parent[parent[x]]
            x = parent[x]
        return x

    def union(x, y):
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if rank[rx] < rank[ry]:
            parent[rx] = ry
        elif rank[rx] > rank[ry]:
            parent[ry] = rx
        else:
            parent[ry] = rx
            rank[rx] += 1

    zero_emp = 0
    used_lang = [False] * (m + 1)

    for _ in range(n):
        k = int(next(it))
        if k == 0:
            zero_emp += 1
            continue
        langs = [int(next(it)) for _ in range(k)]
        first = langs[0]
        used_lang[first] = True
        for lang in langs[1:]:
            used_lang[lang] = True
            union(first, lang)

    # count distinct components among used languages
    comps = set()
    for lang in range(1, m + 1):
        if used_lang[lang]:
            comps.add(find(lang))
    comp_cnt = len(comps)

    if comp_cnt == 0:
        # nobody knows any language
        print(n)
    else:
        # need (comp_cnt - 1) connections between language groups
        # plus each zero-language employee must learn a language
        print(comp_cnt - 1 + zero_emp)

