import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    a = [0] + list(map(int, data[1:]))

    sys.setrecursionlimit(1_000_000)

    state = [0] * (n + 1)          # 0 = unvisited, 1 = in stack, 2 = processed
    cycles = []                    # list of cycles (each a list of vertices)
    self_loop_root = -1

    def dfs(u: int):
        nonlocal self_loop_root
        state[u] = 1
        v = a[u]
        if state[v] == 0:
            dfs(v)
        elif state[v] == 1:
            # found a new cycle starting at v
            cur = v
            cyc = []
            while True:
                cyc.append(cur)
                cur = a[cur]
                if cur == v:
                    break
            cycles.append(cyc)
            if len(cyc) == 1 and a[cyc[0]] == cyc[0]:
                self_loop_root = cyc[0]
        state[u] = 2

    for i in range(1, n + 1):
        if state[i] == 0:
            dfs(i)

    # choose root
    if self_loop_root != -1:
        root = self_loop_root
    else:
        root = cycles[0][0]   # any vertex from first cycle

    p = a[:]                  # result array
    changes = 0

    # make root a self‑loop if it isn't already
    if p[root] != root:
        p[root] = root
        changes += 1

    for cyc in cycles:
        # skip the root's own cycle if it is already a self‑loop
        if root in cyc and len(cyc) == 1 and a[root] == root:
            continue
        # skip the root's own (now broken) cycle
        if root in cyc:
            continue
        v = cyc[0]
        if p[v] != root:
            p[v] = root
            changes += 1

    out = [str(changes), "\n", " ".join(map(str, p[1:]))]
    sys.stdout.write("".join(out))

if __name__ == "__main__":
    solve()

import sys

MOD = 10**9 + 7

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    a = list(map(int, data[1:]))

    # Precompute factorials and inverse factorials
    fact = [1] * (n)
    for i in range(1, n):
        fact[i] = fact[i - 1] * i % MOD
    inv_fact = [1] * (n)
    inv_fact[-1] = pow(fact[-1], MOD - 2, MOD)
    for i in range(n - 2, -1, -1):
        inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD

    def comb(N, K):
        if K < 0 or K > N:
            return 0
        return fact[N] * inv_fact[K] % MOD * inv_fact[N - K] % MOD

    # The coefficient for a[i] is C(n-1, i) * (-1)^{i*(n-1-i)}
    ans = 0
    for i in range(n):
        coeff = comb(n - 1, i)
        if (i * (n - 1 - i)) & 1:
            coeff = MOD - coeff
        ans = (ans + coeff * a[i]) % MOD

    print(ans)


