import sys

MAX_A = 200000

def build_spf(limit: int):
    spf = list(range(limit + 1))
    for i in range(2, int(limit ** 0.5) + 1):
        if spf[i] == i:
            step = i
            start = i * i
            for j in range(start, limit + 1, step):
                if spf[j] == j:
                    spf[j] = i
    return spf

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    n = int(data[0])
    a = list(map(int, data[1:]))

    spf = build_spf(MAX_A)

    INF = 10 ** 9
    cnt = [0] * (MAX_A + 1)
    first = [INF] * (MAX_A + 1)
    second = [INF] * (MAX_A + 1)

    for val in a:
        x = val
        while x > 1:
            p = spf[x]
            e = 0
            while x % p == 0:
                x //= p
                e += 1
            cnt[p] += 1
            if e < first[p]:
                second[p] = first[p]
                first[p] = e
            elif e < second[p]:
                second[p] = e

    ans = 1
    for p in range(2, MAX_A + 1):
        if cnt[p] == 0:
            continue
        zeros = n - cnt[p]
        if zeros >= 2:
            exp = 0
        elif zeros == 1:
            exp = first[p]
        else:  # zeros == 0
            exp = second[p]
        if exp:
            ans *= pow(p, exp)

    print(ans)

if __name__ == "__main__":
    solve()
